/**
 * UX Review — manifest loader + shared types.
 *
 * Data source: projects/UX Review/app-map.json, generated by Project B from
 * the Luna App Map. The manifest is a flat array per the artifact contract
 * (INFRASTRUCTURE-BRIEF §6). Design-version config lives here (platform
 * concern, not part of the artifact contract).
 */
import rawManifest from "../../projects/UX Review/app-map.json";

export type ScreenStatus = "Work in Progress" | "Approved";

export interface Screen {
  id: string;
  title: string;
  /** Review workflow status. */
  status: ScreenStatus;
  feature: string;
  /** Path to the wireframe artifact, or `component:<id>` for a native render. */
  wireframe: string;
  /** Legacy (Figma screenshot) for the old-vs-new compare; null when none. */
  legacy: string | null;
  summary?: string;
}

export const SCREENS: Screen[] = rawManifest as Screen[];

/** Design versions a comment can be stamped against (newest last). */
export const DESIGN_VERSIONS = ["v0.1 — Apr 2026", "v0.2 — May 2026", "v0.3 — Jun 2026", "v0.4 — Jun 2026", "v0.5 — Jun 2026"] as const;
export const CURRENT_DESIGN_VERSION = "v0.5 — Jun 2026";

export const STATUS_ORDER: ScreenStatus[] = ["Work in Progress", "Approved"];

/**
 * Scenario states — the dynamic-content axis. Some screens change over time
 * (e.g. Hypo Shield's communication differs on day one vs. mid-learning vs.
 * ready). A screen listed here renders ALL its states into the DOM (each block
 * wrapped in `[data-ux-state="<id>"]`, the first visible and the rest `hidden`)
 * and the detail page shows a segmented "Scenario" control above the phone so a
 * reviewer can switch between them. Orthogonal to the New/Old variant and the
 * design-version dropdown. First entry is the default shown on load.
 */
export interface ScreenState {
  id: string;
  /** Short control label (e.g. "Days 1–7 · Establishing"). */
  label: string;
  /** One line under the control explaining what the reviewer is looking at. */
  caption: string;
}
export const SCREEN_STATES: Record<string, ScreenState[]> = {
  "hypo-learning-state": [
    {
      id: "early",
      label: "Getting to know you",
      caption: "Your first Luna sessions. Hypo Shield is learning your nights and dosing conservatively to avoid lows — no suggestions yet. Threshold is 7 Luna sessions (they don't need to be consecutive).",
    },
    {
      id: "almost",
      label: "Almost there",
      caption: "Most of the way to unlocking suggestions — gamified to nudge the user over the line (e.g. \"2 more sessions to go\"). After the 7th session the first suggestion appears directly (no separate \"ready\" screen).",
    },
  ],
};
export function statesFor(id: string): ScreenState[] {
  return SCREEN_STATES[id] ?? [];
}

export function getScreen(id: string): Screen | undefined {
  return SCREENS.find((s) => s.id === id);
}

/** Distinct features, in first-seen order. */
export function features(): string[] {
  return [...new Set(SCREENS.map((s) => s.feature))];
}

/** Screens grouped by feature, preserving feature first-seen order. */
export function byFeature(): { feature: string; screens: Screen[] }[] {
  return features().map((feature) => ({
    feature,
    screens: SCREENS.filter((s) => s.feature === feature),
  }));
}

/** If the wireframe is a native component render, return its registry id. */
export function componentId(wireframe: string | null): string | null {
  if (!wireframe) return null;
  return wireframe.startsWith("component:") ? wireframe.slice("component:".length) : null;
}

